      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  if (!f.getItemValue('ngay_vao2')) f.setItemValue('ngay_vao2', new Date());
  changeLookupReadonly(f, 'ma_ttnv', true);
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, d1 = f.getItem('ngay_vao1').value, d2 = f.getItem('ngay_vao2').value;
      var s = '', v1 = f.getItemValue('ngay_vao1'), v2 = f.getItemValue('ngay_vao2');
      if (v1 == null && v2 != null) s = f._language == 'v' ? ('Ngày vào công ty đến ngày: ' + d2) : ('Date in to: ' + d2);
      else if (v1 != null && v2 == null) s = f._language == 'v' ? ('Ngày vào công ty từ ngày: ' + d1) : ('Date in from: ' + d1);
      else s = f._language == 'v' ? ('Ngày vào công ty từ ngày ' + d1 + ' đến ' + d2) : ('Date in from ' + d1 + ' to ' + d2);
      g._alterTitle = [null, [['%s', s, true]]];
      if (g._$k != null) g._$k = [];
      break;
    default:
      break;
  }
}
